import psutil
import os
import signal
import time

def is_process_running(process_name):
    """Check if a process with the given name is running."""
    for proc in psutil.process_iter(['pid', 'name']):
        try:
            if proc.info['name'] == process_name:
                return True
        except (psutil.NoSuchProcess, psutil.AccessDenied, psutil.ZombieProcess):
            pass
    return False

def restart_process(process_path):
    """Restart the process by killing it and starting it again."""
    process_name = os.path.basename(process_path)

    if is_process_running(process_name):
        for proc in psutil.process_iter(['pid', 'name']):
            try:
                if proc.info['name'] == process_name:
                    os.kill(proc.info['pid'], signal.SIGKILL)
            except (psutil.NoSuchProcess, psutil.AccessDenied, psutil.ZombieProcess):
                pass

    os.system(f"python3 {process_path} &")

if __name__ == "__main__":
    process_path = "/full/path/dashboard/live_state_updater.py"

    # Test assertions
    assert is_process_running("live_state_updater.py") == False, "Process should not be running initially."

    restart_process(process_path)
    time.sleep(1)  # Allow some time for the process to start

    assert is_process_running("live_state_updater.py") == True, "Process should be running after restarting."

    os.system(f"kill -9 $(pgrep -f {process_path})")
    time.sleep(1)  # Allow some time for the process to stop

    assert is_process_running("live_state_updater.py") == False, "Process should not be running after being killed."

    restart_process(process_path)
    time.sleep(60)  # Wait for the cron job to run and check if it restarts

    assert is_process_running("live_state_updater.py") == True, "Process should be running after cron job restarts."
